package main

import (
	"fmt"
	"html"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It retrieves the keyword from the query parameter and displays it in the page title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get the keyword from the URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks before embedding in HTML
	escapedKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	// Displaying the user's search keyword in the page title area
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Product search results would go here -->
</body>
</html>`, escapedKeyword)

	// Write the HTML content to the response
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on http://localhost:8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server failed: %s\n", err)
	}
}

