package main

import (
	"fmt"
	"html"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It retrieves the 'keyword' query parameter and displays it in the HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get the keyword from the query string
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks before displaying it
	escapedKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <!-- Product list would go here -->
</body>
</html>`, escapedKeyword)

	// Write the response
	w.Write([]byte(htmlContent))
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on http://localhost:8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server failed: %s\n", err)
	}
}

