package main

import (
	"fmt"
	"html/template"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request.
// It retrieves the keyword from the query parameters and renders an HTML page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Ensure the method is GET
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Get the keyword from the query string
	keyword := r.URL.Query().Get("keyword")

	// Prepare data for the template
	data := struct {
		Keyword string
		Time    string
	}{
		Keyword: keyword,
		Time:    time.Now().Format(time.RFC1123),
	}

	// Define the HTML template
	const tpl = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .container { max-width: 800px; margin: 0 auto; }
        .header { border-bottom: 1px solid #eee; padding-bottom: 10px; margin-bottom: 20px; }
        .results { color: #555; }
        .analytics-info { font-size: 0.8em; color: #999; margin-top: 40px; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>Search Results: {{.Keyword}}</h2>
        </div>
        <div class="results">
            <p>Displaying results for "{{.Keyword}}".</p>
            <p><em>(No actual products found in this demo.)</em></p>
        </div>
        <div class="analytics-info">
            Page generated at: {{.Time}}
        </div>
    </div>
</body>
</html>
`

	// Parse the template
	t, err := template.New("search").Parse(tpl)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Error parsing template: %v", err)
		return
	}

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template
	err = t.Execute(w, data)
	if err != nil {
		log.Printf("Error executing template: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on http://localhost:8080/search?keyword=test")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

