    </div>
</body>
</html>
`

	// Parse the template
	t, err := template.New("search").Parse(tpl)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Error parsing template: %v", err)
		return
	}

	// Execute the template with the keyword
	err = t.Execute(w, keyword)
	if err != nil {
		log.Printf("Error executing template: %v", err)
	}
