package main

import (
	"fmt"
	"net/http"
)

// HandleProductSearch handles the product search request.
// It retrieves the 'keyword' query parameter, sets the content type to HTML,
// and displays the search results page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Retrieve the keyword from the URL query parameters.
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to text/html.
	w.Header().Set("Content-Type", "text/html")

	// Write the HTML response.
	// We use fmt.Fprintf to construct the HTML content dynamically.
	fmt.Fprintf(w, `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .results { margin-top: 20px; color: #333; }
    </style>
</head>
<body>
    <h2>Search Results: %s</h2>
    <div class="results">
        <p>Displaying results for your search...</p>
    </div>
</body>
</html>`, keyword)
}

func main() {
	// Register the handler for the "/search" route.
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080.
	fmt.Println("Server starting on http://localhost:8080/search")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Error starting server: %s\n", err)
	}
}

