	"time"
)

// HandleProductSearch handles the product search request.
// It retrieves the keyword from the query parameters, records analytics data,
// and renders the search results page.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Ensure the method is GET
	if r.Method != http.MethodGet {
		http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics Logic: Log the search event
	// In a real application, this might be sent to a service like Google Analytics,
	// written to a database, or sent to a message queue.
	log.Printf("Analytics: [Search] UserIP=%s, Keyword=%q, Timestamp=%s", r.RemoteAddr, keyword, time.Now().Format(time.RFC3339))

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Define the HTML template
	const htmlTemplate = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .search-header { background-color: #f4f4f4; padding: 20px; border-radius: 5px; }
        .results { margin-top: 20px; }
        .product-card { border: 1px solid #ddd; padding: 15px; margin-bottom: 10px; border-radius: 5px; }
    </style>
</head>
<body>
    <div class="search-header">
        <h2>Search Results: {{.Keyword}}</h2>
    </div>

    <div class="results">
        <p>Displaying results for "<strong>{{.Keyword}}</strong>"...</p>

        <!-- Mock Product Results -->
        <div class="product-card">
            <h3>Product A</h3>
            <p>Description for Product A related to {{.Keyword}}.</p>
        </div>
        <div class="product-card">
            <h3>Product B</h3>
            <p>Description for Product B related to {{.Keyword}}.</p>
        </div>
    </div>
</body>
</html>
`

	// Execute the template
	tmpl, err := template.New("search").Parse(htmlTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		log.Printf("Error parsing template: %v", err)
		return
	}

	// Create data to pass to the template
	data := struct {
		Keyword string
	}{
		Keyword: keyword,
	}

	// Render the template to the response writer
	if err := tmpl.Execute(w, data); err != nil {
		log.Printf("Error executing template: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on http://localhost:8080/search?keyword=test")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

